class Solution:
    def numSteps(self, s: str) -> int:
        steps = 0
        carry = 0
        for i in range(len(s) - 1, 0, -1):
            bit = int(s[i]) + carry
            if bit == 0:
                steps += 1
                carry = 0
            elif bit == 1:
                steps += 2
                carry = 1
            else:  # bit == 2 (1 + carry=1)
                steps += 1
                carry = 1
        # If carry propagated into the leading '1', one more shift is needed
        if carry == 1:
            steps += 1
        return steps

