var numSteps = function(s) {
    let steps = 0;
    let carry = 0;
    for (let i = s.length - 1; i > 0; i--) {
        const bit = parseInt(s[i]) + carry;
        if (bit === 0) {
            steps += 1;
            carry = 0;
        } else if (bit === 1) {
            steps += 2;
            carry = 1;
        } else {
            steps += 1;
            carry = 1;
        }
    }
    if (carry === 1) steps += 1;
    return steps;
};
